/**
 * Structural snapshot of the cerebrum pillar's public surface. The
 * `CerebrumContract` type lives in `manifest.generated.ts` and is regenerated by
 * `pnpm -F @pops/cerebrum generate:manifest`. This file is the stable import path
 * (`@pops/cerebrum/manifest`) so downstream consumers don't move with the
 * generator output.
 *
 * The runtime `ModuleManifest` values for `cerebrum` and `ego` are exported here;
 * the registry's workspace discovery walk
 * (`libs/module-registry/scripts/known-modules.ts`) consumes them on build.
 *
 * `ego` is co-located here because its settings nest under cerebrum; the pillar
 * does not have its own contract package.
 */
import {
  cerebrumManifest as cerebrumSettingsManifest,
  egoManifest as egoSettingsManifest,
} from './settings/index.js';

import type { ModuleManifest } from '@pops/types';

export type { CerebrumContract } from './manifest.generated.js';

export const cerebrumManifest: ModuleManifest = {
  id: 'cerebrum',
  name: 'Cerebrum',
  version: '0.1.0',
  surfaces: ['app'],
  description:
    'Engram storage, retrieval, ingest/emit, plexus, reflex, glia — knowledge graph and agents.',
  settings: [cerebrumSettingsManifest],
};

export const egoManifest: ModuleManifest = {
  id: 'ego',
  name: 'Ego',
  version: '0.1.0',
  surfaces: ['app', 'overlay'],
  description: 'Conversational AI interface to Cerebrum (PRD-087).',
  frontend: {
    overlay: {
      chromeSlot: 'assistant',
      shortcut: 'mod+i',
    },
  },
  settings: [egoSettingsManifest],
};
